INSERT INTO `documents` (`id`, `title`, `content`, `user_id`, `category`, `tags`, `permission`, `view_count`, `created_at`, `updated_at`, `like_count`, `comment_count`, `collection_count`) VALUES
	(112, 'JavaScript 基础教程', '# JavaScript 基础教程\n\n## 变量声明\n\n```javascript\nlet name = "张三";\nconst age = 25;\nvar job = "工程师";\n```\n\n## 数据类型\n\n- String\n- Number\n- Boolean\n- Array\n- Object\n\n## 函数\n\n```javascript\nfunction greet(name) {\n  return `Hello, ${name}!`;\n}\n```', 4, 'work', 'JavaScript,基础,教程', 'public', 177, '2026-04-18 03:38:23', '2026-04-18 17:27:55', 3, 0, 0),
	(114, 'CSS3 高级技巧', '# CSS3 高级技巧\n\n## 选择器\n\n- 属性选择器\n- 伪类选择器\n- 伪元素选择器\n\n## 动画\n\n```css\n@keyframes fadeIn {\n  from { opacity: 0; }\n  to { opacity: 1; }\n}\n\n.element {\n  animation: fadeIn 1s ease-in-out;\n}\n```\n\n## Flexbox\n\n```css\n.container {\n  display: flex;\n  justify-content: center;\n  align-items: center;\n}\n```', 4, 'tech', 'CSS3,前端,样式', 'public', 90, '2026-04-18 03:38:23', '2026-04-18 08:52:05', 0, 0, 0),
	(115, 'React 组件开发', '# React 组件开发\n\n## 函数组件\n\n```jsx\nfunction Greeting({ name }) {\n  return <h1>Hello, {name}!</h1>;\n}\n```\n\n## Hooks\n\n- useState\n- useEffect\n- useContext\n- useReducer\n\n## 生命周期\n\n- componentDidMount\n- componentDidUpdate\n- componentWillUnmount', 4, 'entertainment', 'React,前端,组件', 'public', 112, '2026-04-18 03:38:23', '2026-04-18 08:52:11', 0, 0, 0),
	(116, 'Node.js 入门', '# Node.js 入门\n\n## 安装\n\n```bash\nnpm install node\n```\n\n## 基本模块\n\n- fs\n- http\n- path\n- os\n\n## 包管理\n\n```bash\nnpm init\nnpm install express\n```', 5, 'other', 'Node.js,后端,教程', 'public', 87, '2026-04-18 03:38:23', '2026-04-18 16:49:39', 0, 0, 0),
	(117, 'Express 框架', '# Express 框架\n\n## 基本用法\n\n```javascript\nconst express = require("express");\nconst app = express();\n\napp.get("/", (req, res) => {\n  res.send("Hello World!");\n});\n\napp.listen(3000);\n```\n\n## 中间件\n\n- 路由中间件\n- 错误处理中间件\n- 静态文件中间件', 4, 'tech', 'Express,Node.js,后端', 'private', 68, '2026-04-18 03:38:23', '2026-04-18 03:38:23', 0, 0, 0),
	(118, 'MongoDB 数据库', '# MongoDB 数据库\n\n## 连接\n\n```javascript\nconst mongoose = require("mongoose");\nmongoose.connect("mongodb://localhost:27017/mydb");\n```\n\n## 模型\n\n```javascript\nconst userSchema = new mongoose.Schema({\n  name: String,\n  age: Number\n});\n\nconst User = mongoose.model("User", userSchema);\n```\n\n## 查询\n\n```javascript\nUser.find({ age: { $gt: 18 } });\n```', 4, 'work', 'MongoDB,数据库,NoSQL', 'secret', 89, '2026-04-18 03:38:23', '2026-04-18 03:38:23', 0, 0, 0),
	(119, 'Git 版本控制', '# Git 版本控制\n\n## 基本命令\n\n- `git init`\n- `git add .`\n- `git commit -m "message"`\n- `git push`\n- `git pull`\n\n## 分支管理\n\n- `git branch`\n- `git checkout -b branchname`\n- `git merge branchname`\n\n## 远程仓库\n\n- `git remote add origin url`\n- `git push -u origin main`', 4, 'work', 'Git,版本控制,工具', 'private', 103, '2026-04-18 03:38:23', '2026-04-18 03:38:23', 0, 0, 0),
	(120, 'Docker 容器化', '# Docker 容器化\n\n## 基本命令\n\n- `docker build -t imageName .`\n- `docker run -p 8080:8080 imageName`\n- `docker ps`\n- `docker stop containerId`\n\n## Dockerfile\n\n```dockerfile\nFROM node:14\nWORKDIR /app\nCOPY . .\nRUN npm install\nEXPOSE 3000\nCMD ["npm", "start"]\n```', 6, 'entertainment', 'Docker,容器,DevOps', 'private', 91, '2026-04-18 03:38:23', '2026-04-18 17:10:37', 2, 0, 0),
	(121, 'RESTful API 设计', '# RESTful API 设计\n\n## HTTP 方法\n\n- GET: 获取资源\n- POST: 创建资源\n- PUT: 更新资源\n- DELETE: 删除资源\n\n## 状态码\n\n- 200: OK\n- 201: Created\n- 400: Bad Request\n- 404: Not Found\n- 500: Internal Server Error\n\n## 最佳实践\n\n- 使用 HTTPS\n- 版本控制\n- 错误处理\n- 限流', 4, 'tech', 'API,REST,后端', 'private', 78, '2026-04-18 03:38:23', '2026-04-18 03:38:23', 0, 0, 0),
	(122, 'TypeScript 基础', '# TypeScript 基础\n\n## 类型系统\n\n- number\n- string\n- boolean\n- any\n- unknown\n\n## 接口\n\n```typescript\ninterface User {\n  id: number;\n  name: string;\n  age: number;\n}\n```\n\n## 泛型\n\n```typescript\nfunction identity<T>(arg: T): T {\n  return arg;\n}\n```', 4, 'life', 'TypeScript,JavaScript,类型', 'private', 85, '2026-04-18 03:38:23', '2026-04-18 03:38:23', 0, 0, 0),
	(123, 'Vue 3 新特性', '# Vue 3 新特性\n\n## Composition API\n\n```javascript\nimport { ref, computed } from "vue"\n\nexport default {\n  setup() {\n    const count = ref(0)\n    const doubleCount = computed(() => count.value * 2)\n    return { count, doubleCount }\n  }\n}\n```\n\n## Teleport\n\n```vue\n<teleport to="#modal">\n  <div class="modal">\n    Modal content\n  </div>\n</teleport>\n```\n\n## Suspense\n\n```vue\n<Suspense>\n  <template #default>\n    <AsyncComponent />\n  </template>\n  <template #fallback>\n    Loading...\n  </template>\n</Suspense>\n```', 5, 'entertainment', 'Vue 3,前端,框架', 'private', 73, '2026-04-18 03:38:23', '2026-04-18 08:01:46', 0, 0, 0),
	(124, 'GraphQL 入门', '# GraphQL 入门\n\n## 查询\n\n```graphql\nquery {\n  users {\n    id\n    name\n    email\n  }\n}\n```\n\n## 变更\n\n```graphql\nmutation {\n  createUser(name: "John", email: "john@example.com") {\n    id\n    name\n  }\n}\n```\n\n## 优点\n\n- 按需获取数据\n- 类型系统\n- 单一端点\n- 实时更新', 4, 'other', 'API', 'private', 69, '2026-04-18 03:38:23', '2026-04-18 03:38:23', 1, 0, 0),
	(125, 'Redis 缓存', '# Redis 缓存\n\n## 数据类型\n\n- String\n- List\n- Set\n- Hash\n- Sorted Set\n\n## 基本命令\n\n- SET key value\n- GET key\n- DEL key\n- EXPIRE key seconds\n\n## 应用场景\n\n- 缓存\n- 会话管理\n- 排行榜\n- 消息队列', 4, 'life', 'Redis,缓存,数据库', 'private', 82, '2026-04-18 03:38:23', '2026-04-18 03:38:23', 1, 0, 0),
	(126, 'React Native 开发', '# React Native 开发\n\n## 环境搭建\n\n```bash\nnpm install -g expo-cli\nexpo init my-project\n```\n\n## 组件\n\n```jsx\nimport { View, Text, StyleSheet } from "react-native"\n\nexport default function App() {\n  return (\n    <View style={styles.container}>\r\n      <Text>Hello World!</Text>\n    </View>\n  )\n}\n\nconst styles = StyleSheet.create({\n  container: {\n    flex: 1,\n    alignItems: "center",\n    justifyContent: "center"\n  }\n})\n```', 4, 'other', 'React Native,移动开发,跨平台', 'private', 75, '2026-04-18 03:38:23', '2026-04-18 03:38:23', 0, 0, 0),
	(127, 'Flutter 入门', '# Flutter 入门\n\n## 环境搭建\n\n- 安装 Flutter SDK\n- 配置环境变量\n- 安装 Android Studio\n\n## 基本组件\n\n- Container\n- Text\n- Image\n- Button\n- ListView\n\n## 状态管理\n\n- setState\n- Provider\n- Bloc\n- Riverpod', 5, 'life', 'Flutter,移动开发,Dart', 'public', 90, '2026-04-18 03:38:23', '2026-04-18 08:52:30', 0, 0, 0),
	(128, 'AWS 云服务', '# AWS 云服务\n\n## 核心服务\n\n- EC2: 虚拟服务器\n- S3: 对象存储\n- RDS: 关系型数据库\n- Lambda: 无服务器函数\n- API Gateway: API 管理\n\n## 部署流程\n\n1. 创建 EC2 实例\n2. 配置安全组\n3. 部署应用\n4. 配置负载均衡\n\n## 监控\n\n- CloudWatch\n- CloudTrail\n- X-Ray', 4, 'entertainment', 'AWS,云计算,DevOps', 'private', 94, '2026-04-18 03:38:23', '2026-04-18 03:38:23', 0, 0, 0),
	(129, 'Kubernetes 容器编排', '# Kubernetes 容器编排\n\n## 核心概念\n\n- Pod\n- Deployment\n- Service\n- ConfigMap\n- Secret\n\n## 基本命令\n\n- `kubectl get pods`\n- `kubectl apply -f deployment.yaml`\n- `kubectl logs pod-name`\n- `kubectl exec -it pod-name -- /bin/bash`\n\n## 部署策略\n\n- Rolling Update\n- Blue/Green\n- Canary', 4, 'entertainment', 'Kubernetes,容器,DevOps', 'private', 81, '2026-04-18 03:38:23', '2026-04-18 03:38:23', 0, 0, 0),
	(130, '微服务架构', '# 微服务架构\n\n## 特点\n\n- 服务独立部署\n- 服务独立扩展\n- 技术栈多样化\n- 去中心化管理\n\n## 挑战\n\n- 服务发现\n- 负载均衡\n- 分布式事务\n- 监控和追踪\n\n## 工具\n\n- Eureka\n- Ribbon\n- Feign\n- Hystrix', 4, 'work', '微服务,架构,后端', 'private', 77, '2026-04-18 03:38:23', '2026-04-18 03:38:23', 0, 0, 0),
	(131, 'DevOps 实践', '# DevOps 实践\n\n## CI/CD\n\n- 持续集成\n- 持续部署\n- 自动化测试\n\n## 工具链\n\n- Jenkins\n- GitHub Actions\n- GitLab CI\n- CircleCI\n\n## 监控\n\n- Prometheus\n- Grafana\n- ELK Stack\n- New Relic', 4, 'entertainment', 'DevOps,CI/CD,监控', 'private', 86, '2026-04-18 03:38:23', '2026-04-18 03:38:23', 0, 0, 0),
